objects.draw:
function(ctx, obj) {
  ctx.save();

  // Aplicar rotação
  if (obj.angle) {
    const c = Lab.utils.getCenter(obj);
    ctx.translate(c.x, c.y);
    ctx.rotate(obj.angle * Math.PI / 180);
    ctx.translate(-c.x, -c.y);
  }

  // Corpo do ímã
  ctx.fillStyle = obj.fill;
  ctx.fillRect(obj.x, obj.y, obj.w, obj.h);
  ctx.strokeStyle = obj.stroke;
  ctx.lineWidth = obj.lineWidth || 2;
  ctx.strokeRect(obj.x, obj.y, obj.w, obj.h);

  // Polos N e S
  ctx.fillStyle = '#ffffff';
  ctx.font = `bold ${Math.max(12, obj.h / 2)}px monospace`;
  ctx.fillText('N', obj.x + 8, obj.y + obj.h/2 + 5);
  ctx.fillText('S', obj.x + obj.w - 18, obj.y + obj.h/2 + 5);

  // Linhas de campo magnético (efeito visual)
  if (Lab.state.showMagneticField) {
    ctx.beginPath();
    ctx.strokeStyle = 'rgba(108, 99, 255, 0.4)';
    ctx.lineWidth = 1.5;
    ctx.setLineDash([5, 5]);

    const center = Lab.utils.getCenter(obj);
    const radius = Math.max(obj.w, obj.h) / 2;

    for (let i = 0; i < 8; i++) {
      const angle = (i / 8) * Math.PI * 2;
      const startX = center.x + Math.cos(angle) * radius;
      const startY = center.y + Math.sin(angle) * radius;
      const endX = center.x + Math.cos(angle) * (radius + 40);
      const endY = center.y + Math.sin(angle) * (radius + 40);

      ctx.beginPath();
      ctx.moveTo(startX, startY);
      ctx.quadraticCurveTo(
        center.x + Math.cos(angle + 0.5) * (radius + 20),
        center.y + Math.sin(angle + 0.5) * (radius + 20),
        endX, endY
      );
      ctx.stroke();
    }
    ctx.setLineDash([]);
  }

  ctx.restore();
}

objects.update:
function(obj, dt) {
  if (!Lab.state.isSimulating) return;

  const center = Lab.utils.getCenter(obj);

  for (const other of Lab.state.objects) {
    if (other.id === obj.id) continue;
    if (!other.charge || other.charge === 0) continue;
    if (other.static) continue;

    const otherCenter = Lab.utils.getCenter(other);
    const dx = otherCenter.x - center.x;
    const dy = otherCenter.y - center.y;
    const r = Math.hypot(dx, dy);

    if (r > 8 && r < 200) {
      const B = obj.strength / Math.max(r * r, 25);

      // Força de Lorentz: F = q * v × B
      const forceX = -other.charge * B * dy;
      const forceY = other.charge * B * dx;

      other.vx = (other.vx || 0) + forceX * dt / (other.mass || 1);
      other.vy = (other.vy || 0) + forceY * dt / (other.mass || 1);
    }
  }
}

objects.draw:
function(ctx, obj) {
  ctx.save();

  if (obj.angle) {
    const c = Lab.utils.getCenter(obj);
    ctx.translate(c.x, c.y);
    ctx.rotate(obj.angle * Math.PI / 180);
    ctx.translate(-c.x, -c.y);
  }

  // Corpo do fio
  ctx.fillStyle = obj.fill;
  ctx.fillRect(obj.x, obj.y, obj.w, obj.h);
  ctx.strokeStyle = obj.stroke;
  ctx.lineWidth = obj.lineWidth || 1;
  ctx.strokeRect(obj.x, obj.y, obj.w, obj.h);

  // Corrente (linhas tracejadas)
  ctx.beginPath();
  ctx.strokeStyle = '#000000';
  ctx.lineWidth = 1.5;
  ctx.setLineDash([4, 4]);
  for (let i = 1; i <= 3; i++) {
    const yPos = obj.y + obj.h / 2;
    const xStart = obj.x + i * obj.w / 4;
    ctx.beginPath();
    ctx.moveTo(xStart - 8, yPos);
    ctx.lineTo(xStart, yPos - 4);
    ctx.lineTo(xStart, yPos + 4);
    ctx.closePath();
    ctx.fillStyle = '#000000';
    ctx.fill();
  }
  ctx.setLineDash([]);

  // Texto da corrente
  ctx.fillStyle = '#000000';
  ctx.font = 'bold 10px monospace';
  ctx.fillText(`${obj.current}A`, obj.x + obj.w/2 - 8, obj.y - 5);

  // Linhas de campo (efeito visual)
  if (Lab.state.showMagneticField) {
    const center = Lab.utils.getCenter(obj);
    ctx.beginPath();
    ctx.strokeStyle = 'rgba(108, 99, 255, 0.4)';
    ctx.lineWidth = 1;
    ctx.setLineDash([4, 4]);

    for (let i = 0; i < 12; i++) {
      const angle = (i / 12) * Math.PI * 2;
      const radius = 25;
      const x = center.x + Math.cos(angle) * radius;
      const y = center.y + Math.sin(angle) * radius;

      ctx.beginPath();
      ctx.arc(x, y, 3, 0, Math.PI * 2);
      ctx.fillStyle = 'rgba(108, 99, 255, 0.2)';
      ctx.fill();
    }
    ctx.setLineDash([]);
  }

  ctx.restore();
}

objects.update:
function(obj, dt) {
  if (!Lab.state.isSimulating) return;

  const center = Lab.utils.getCenter(obj);

  for (const other of Lab.state.objects) {
    if (other.id === obj.id) continue;
    if (!other.charge || other.charge === 0) continue;
    if (other.static) continue;

    const otherCenter = Lab.utils.getCenter(other);
    const dx = otherCenter.x - center.x;
    const dy = otherCenter.y - center.y;
    const r = Math.hypot(dx, dy);

    if (r > 5 && r < 150) {
      // Campo magnético de um fio: B = μ0 * I / (2πr)
      const B = (obj.current * 2e-7) / Math.max(r, 10);
      const forceX = -other.charge * B * dy;
      const forceY = other.charge * B * dx;

      other.vx = (other.vx || 0) + forceX * dt / (other.mass || 1);
      other.vy = (other.vy || 0) + forceY * dt / (other.mass || 1);
    }
  }
}

tools.action:
function() {
  Lab.state.showMagneticField = !Lab.state.showMagneticField;
  Lab.render.all();
  alert(Lab.state.showMagneticField ? 'Linhas de campo visíveis' : 'Linhas de campo ocultas');
}

